import React, { useState, useEffect, useCallback } from 'react';
import {
  LayoutDashboard, 
  DollarSign, 
  Users, 
  Monitor, 
  Settings, 
  LogOut,
  Plus,
  Search,
  Edit2,
  Trash2,
  Save,
  X,
  RefreshCw,
  TrendingUp,
  TrendingDown,
  AlertCircle,
  CheckCircle,
  Clock,
  ChevronRight,
  Menu,
  Bell,
  User,
  Calendar,
  Download,
  Upload,
  Filter,
  Globe
} from 'lucide-react';
import './AdminPanel.css';

const AdminPanel = () => {
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [currencies, setCurrencies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [showAddModal, setShowAddModal] = useState(false);
  const [newCurrency, setNewCurrency] = useState({
    name: '',
    code: '',
    selling: '',
    buying: '',
    flag: ''
  });
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [notification, setNotification] = useState(null);

  // Sample data - replace with API call
  useEffect(() => {
    loadSampleData();
  }, []);

  const loadSampleData = () => {
    const sampleData = [
      { id: 1, name: 'United States Dollar', code: 'USD', selling: 153.0501, buying: 156.1111, flag: '🇺🇸', lastUpdated: '2024-03-21T17:15:09' },
      { id: 2, name: 'Euro', code: 'EUR', selling: 181.8235, buying: 185.4599, flag: '🇪🇺', lastUpdated: '2024-03-21T17:15:09' },
      { id: 3, name: 'British Pound', code: 'GBP', selling: 209.2121, buying: 213.3964, flag: '🇬🇧', lastUpdated: '2024-03-21T17:15:09' },
      { id: 4, name: 'Saudi Riyal', code: 'SAR', selling: 43.4859, buying: 44.3556, flag: '🇸🇦', lastUpdated: '2024-03-21T17:15:09' },
      { id: 5, name: 'Chinese Yuan', code: 'CNY', selling: 21.2297, buying: 21.6543, flag: '🇨🇳', lastUpdated: '2024-03-21T17:15:09' },
      { id: 6, name: 'Japanese Yen', code: 'JPY', selling: 0.8750, buying: 0.8950, flag: '🇯🇵', lastUpdated: '2024-03-21T18:33:57' },
      { id: 7, name: 'Australian Dollar', code: 'AUD', selling: 62.5000, buying: 64.2000, flag: '🇦🇺', lastUpdated: '2024-03-21T18:33:57' },
      { id: 8, name: 'Canadian Dollar', code: 'CAD', selling: 57.8000, buying: 59.3000, flag: '🇨🇦', lastUpdated: '2024-03-21T18:33:57' },
      { id: 9, name: 'Swiss Franc', code: 'CHF', selling: 118.5000, buying: 121.0000, flag: '🇨🇭', lastUpdated: '2024-03-21T18:33:57' },
      { id: 10, name: 'UAE Dirham', code: 'AED', selling: 42.5000, buying: 43.8000, flag: '🇦🇪', lastUpdated: '2024-03-21T18:33:57' },
    ];
    setCurrencies(sampleData);
  };

  const handleEdit = (currency) => {
    setEditingId(currency.id);
    setEditForm({
      selling: currency.selling,
      buying: currency.buying
    });
  };

  const handleSave = (id) => {
    setCurrencies(currencies.map(curr => 
      curr.id === id 
        ? { ...curr, selling: parseFloat(editForm.selling), buying: parseFloat(editForm.buying), lastUpdated: new Date().toISOString() }
        : curr
    ));
    setEditingId(null);
    showNotification('Currency rates updated successfully!', 'success');
  };

  const handleCancel = () => {
    setEditingId(null);
  };

  const handleDelete = (id) => {
    if (window.confirm('Are you sure you want to delete this currency?')) {
      setCurrencies(currencies.filter(curr => curr.id !== id));
      showNotification('Currency deleted successfully!', 'warning');
    }
  };

  const handleAddCurrency = () => {
    if (!newCurrency.name || !newCurrency.code || !newCurrency.selling || !newCurrency.buying) {
      showNotification('Please fill all fields', 'error');
      return;
    }
    const newId = Math.max(...currencies.map(c => c.id)) + 1;
    setCurrencies([...currencies, {
      ...newCurrency,
      id: newId,
      selling: parseFloat(newCurrency.selling),
      buying: parseFloat(newCurrency.buying),
      lastUpdated: new Date().toISOString()
    }]);
    setNewCurrency({ name: '', code: '', selling: '', buying: '', flag: '' });
    setShowAddModal(false);
    showNotification('Currency added successfully!', 'success');
  };

  const handleRefresh = () => {
    setLoading(true);
    setTimeout(() => {
      loadSampleData();
      setLastUpdated(new Date());
      setLoading(false);
      showNotification('Exchange rates refreshed!', 'info');
    }, 1000);
  };

  const showNotification = (message, type) => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const filteredCurrencies = currencies.filter(curr =>
    curr.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    curr.code.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const stats = {
    totalCurrencies: currencies.length,
    avgSpread: (currencies.reduce((sum, curr) => sum + (curr.buying - curr.selling), 0) / currencies.length).toFixed(4),
    highestRate: [...currencies].sort((a, b) => b.selling - a.selling)[0],
    lastUpdate: lastUpdated.toLocaleString()
  };

  const renderDashboard = () => (
    <div className="dashboard-container">
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon blue"><DollarSign size={24} /></div>
          <div className="stat-info">
            <h3>Total Currencies</h3>
            <p className="stat-value">{stats.totalCurrencies}</p>
            <span className="stat-trend">+2 this month</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon green"><TrendingUp size={24} /></div>
          <div className="stat-info">
            <h3>Average Spread</h3>
            <p className="stat-value">{stats.avgSpread}</p>
            <span className="stat-trend">ETB</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon purple"><Globe size={24} /></div>
          <div className="stat-info">
            <h3>Highest Rate</h3>
            <p className="stat-value">{stats.highestRate?.code}</p>
            <span className="stat-trend">{stats.highestRate?.selling} ETB</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon orange"><Clock size={24} /></div>
          <div className="stat-info">
            <h3>Last Update</h3>
            <p className="stat-value">{new Date().toLocaleTimeString()}</p>
            <span className="stat-trend">{new Date().toLocaleDateString()}</span>
          </div>
        </div>
      </div>

      <div className="recent-activities">
        <h3>Recent Activities</h3>
        <div className="activity-list">
          {currencies.slice(0, 5).map(curr => (
            <div key={curr.id} className="activity-item">
              <div className="activity-icon"><RefreshCw size={16} /></div>
              <div className="activity-content">
                <p><strong>{curr.name} ({curr.code})</strong> rates updated</p>
                <small>{new Date(curr.lastUpdated).toLocaleString()}</small>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const renderCurrencies = () => (
    <div className="currencies-container">
      <div className="section-header">
        <h2>Currency Management</h2>
        <div className="header-actions">
          <div className="search-box">
            <Search size={18} />
            <input
              type="text"
              placeholder="Search by currency name or code..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="btn-primary" onClick={() => setShowAddModal(true)}>
            <Plus size={18} /> Add Currency
          </button>
          <button className="btn-secondary" onClick={handleRefresh}>
            <RefreshCw size={18} className={loading ? 'spin' : ''} /> Refresh
          </button>
        </div>
      </div>

      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Currency</th>
              <th>Code</th>
              <th>Selling Rate (ETB)</th>
              <th>Buying Rate (ETB)</th>
              <th>Spread</th>
              <th>Last Updated</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredCurrencies.map(currency => (
              <tr key={currency.id} className={editingId === currency.id ? 'editing' : ''}>
                <td>
                  <div className="currency-info">
                    <span className="currency-flag">{currency.flag}</span>
                    <span className="currency-name">{currency.name}</span>
                  </div>
                </td>
                <td><span className="currency-code">{currency.code}</span></td>
                <td className="rate-cell">
                  {editingId === currency.id ? (
                    <input
                      type="number"
                      step="0.0001"
                      value={editForm.selling}
                      onChange={(e) => setEditForm({ ...editForm, selling: e.target.value })}
                      className="edit-input"
                    />
                  ) : (
                    <span className="selling-rate">{currency.selling.toFixed(4)}</span>
                  )}
                </td>
                <td className="rate-cell">
                  {editingId === currency.id ? (
                    <input
                      type="number"
                      step="0.0001"
                      value={editForm.buying}
                      onChange={(e) => setEditForm({ ...editForm, buying: e.target.value })}
                      className="edit-input"
                    />
                  ) : (
                    <span className="buying-rate">{currency.buying.toFixed(4)}</span>
                  )}
                </td>
                <td>
                  <span className={`spread ${(currency.buying - currency.selling) > 3 ? 'high' : 'normal'}`}>
                    {(currency.buying - currency.selling).toFixed(4)}
                  </span>
                </td>
                <td className="date-cell">
                  {new Date(currency.lastUpdated).toLocaleString()}
                </td>
                <td className="actions-cell">
                  {editingId === currency.id ? (
                    <>
                      <button className="action-btn save" onClick={() => handleSave(currency.id)}>
                        <Save size={16} /> Save
                      </button>
                      <button className="action-btn cancel" onClick={handleCancel}>
                        <X size={16} /> Cancel
                      </button>
                    </>
                  ) : (
                    <>
                      <button className="action-btn edit" onClick={() => handleEdit(currency)}>
                        <Edit2 size={16} /> Edit
                      </button>
                      <button className="action-btn delete" onClick={() => handleDelete(currency.id)}>
                        <Trash2 size={16} /> Delete
                      </button>
                    </>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="table-footer">
        <div className="pagination-info">
          Showing {filteredCurrencies.length} of {currencies.length} currencies
        </div>
        <div className="last-updated">
          <Clock size={14} />
          Last updated: {new Date().toLocaleString()}
        </div>
      </div>
    </div>
  );

  const renderDevices = () => (
    <div className="devices-container">
      <div className="section-header">
        <h2>Display Devices</h2>
        <button className="btn-primary"><Plus size={18} /> Add Device</button>
      </div>
      <div className="devices-grid">
        <div className="device-card">
          <div className="device-header">
            <Monitor size={24} />
            <span className="device-status active">Active</span>
          </div>
          <h3>Main Lobby Display</h3>
          <p>Location: Main Entrance</p>
          <p>Last Seen: 2 minutes ago</p>
          <p>Playlist: Exchange Rates</p>
        </div>
        <div className="device-card">
          <div className="device-header">
            <Monitor size={24} />
            <span className="device-status active">Active</span>
          </div>
          <h3>Branch 1 - Addis</h3>
          <p>Location: Bole Branch</p>
          <p>Last Seen: 5 minutes ago</p>
          <p>Playlist: Exchange Rates + Promo</p>
        </div>
        <div className="device-card">
          <div className="device-header">
            <Monitor size={24} />
            <span className="device-status inactive">Inactive</span>
          </div>
          <h3>Branch 2 - Mekelle</h3>
          <p>Location: Mekelle Branch</p>
          <p>Last Seen: 2 hours ago</p>
          <p>Playlist: Exchange Rates</p>
        </div>
      </div>
    </div>
  );

  const renderSettings = () => (
    <div className="settings-container">
      <div className="section-header">
        <h2>System Settings</h2>
      </div>
      <div className="settings-grid">
        <div className="setting-card">
          <h3>Exchange Rate Settings</h3>
          <div className="setting-item">
            <label>Auto-refresh Interval</label>
            <select>
              <option>30 seconds</option>
              <option>1 minute</option>
              <option>5 minutes</option>
              <option>15 minutes</option>
            </select>
          </div>
          <div className="setting-item">
            <label>Decimal Places</label>
            <select>
              <option>2 decimals</option>
              <option>4 decimals</option>
              <option>6 decimals</option>
            </select>
          </div>
        </div>
        <div className="setting-card">
          <h3>Display Settings</h3>
          <div className="setting-item">
            <label>Theme</label>
            <select>
              <option>Light</option>
              <option>Dark</option>
              <option>Auto</option>
            </select>
          </div>
          <div className="setting-item">
            <label>Language</label>
            <select>
              <option>English</option>
              <option>Amharic</option>
            </select>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="admin-panel">
      {/* Notification Toast */}
      {notification && (
        <div className={`notification ${notification.type}`}>
          {notification.type === 'success' && <CheckCircle size={20} />}
          {notification.type === 'error' && <AlertCircle size={20} />}
          {notification.type === 'info' && <RefreshCw size={20} />}
          <span>{notification.message}</span>
        </div>
      )}

      {/* Top Navigation Bar */}
      <nav className="top-nav">
        <div className="nav-left">
          <button className="menu-toggle" onClick={() => setSidebarOpen(!sidebarOpen)}>
            <Menu size={24} />
          </button>
          <div className="logo">
            <DollarSign size={28} />
            <span>Digital Signage</span>
          </div>
        </div>
        
        <div className="nav-center">
          <button 
            className={`nav-item ${activeMenu === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActiveMenu('dashboard')}
          >
            <LayoutDashboard size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            className={`nav-item ${activeMenu === 'currencies' ? 'active' : ''}`}
            onClick={() => setActiveMenu('currencies')}
          >
            <DollarSign size={18} />
            <span>Currencies</span>
          </button>
          <button 
            className={`nav-item ${activeMenu === 'devices' ? 'active' : ''}`}
            onClick={() => setActiveMenu('devices')}
          >
            <Monitor size={18} />
            <span>Devices</span>
          </button>
          <button 
            className={`nav-item ${activeMenu === 'settings' ? 'active' : ''}`}
            onClick={() => setActiveMenu('settings')}
          >
            <Settings size={18} />
            <span>Settings</span>
          </button>
        </div>
        
        <div className="nav-right">
          <button className="icon-btn">
            <Bell size={20} />
            <span className="badge">3</span>
          </button>
          <div className="user-menu">
            <User size={20} />
            <span>Admin</span>
          </div>
          <button className="logout-btn">
            <LogOut size={20} />
          </button>
        </div>
      </nav>

      {/* Main Content */}
      <main className="main-content">
        {activeMenu === 'dashboard' && renderDashboard()}
        {activeMenu === 'currencies' && renderCurrencies()}
        {activeMenu === 'devices' && renderDevices()}
        {activeMenu === 'settings' && renderSettings()}
      </main>

      {/* Add Currency Modal */}
      {showAddModal && (
        <div className="modal-overlay" onClick={() => setShowAddModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Add New Currency</h2>
              <button className="close-btn" onClick={() => setShowAddModal(false)}>
                <X size={20} />
              </button>
            </div>
            <div className="modal-body">
              <div className="form-group">
                <label>Currency Name</label>
                <input
                  type="text"
                  placeholder="e.g., United States Dollar"
                  value={newCurrency.name}
                  onChange={(e) => setNewCurrency({ ...newCurrency, name: e.target.value })}
                />
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Currency Code</label>
                  <input
                    type="text"
                    placeholder="e.g., USD"
                    value={newCurrency.code}
                    onChange={(e) => setNewCurrency({ ...newCurrency, code: e.target.value.toUpperCase() })}
                  />
                </div>
                <div className="form-group">
                  <label>Flag Emoji</label>
                  <input
                    type="text"
                    placeholder="e.g., 🇺🇸"
                    value={newCurrency.flag}
                    onChange={(e) => setNewCurrency({ ...newCurrency, flag: e.target.value })}
                  />
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Selling Rate (ETB)</label>
                  <input
                    type="number"
                    step="0.0001"
                    placeholder="0.0000"
                    value={newCurrency.selling}
                    onChange={(e) => setNewCurrency({ ...newCurrency, selling: e.target.value })}
                  />
                </div>
                <div className="form-group">
                  <label>Buying Rate (ETB)</label>
                  <input
                    type="number"
                    step="0.0001"
                    placeholder="0.0000"
                    value={newCurrency.buying}
                    onChange={(e) => setNewCurrency({ ...newCurrency, buying: e.target.value })}
                  />
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-secondary" onClick={() => setShowAddModal(false)}>Cancel</button>
              <button className="btn-primary" onClick={handleAddCurrency}>Add Currency</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;
